    82→#ifndef __MINGW32__
    83→static int
    84→setnonblocking(int fd)
    85→{
    86→    int flags;
    87→    if (-1 == (flags = fcntl(fd, F_GETFL, 0))) {
    88→        flags = 0;
    89→    }
    90→    return fcntl(fd, F_SETFL, flags | O_NONBLOCK);
    91→}
    92→
