    95→static void
    96→build_config(char *prefix, struct server *server)
    97→{
    98→    char *path    = NULL;
    99→    int path_size = strlen(prefix) + strlen(server->port) + 20;
   100→
   101→    path = ss_malloc(path_size);
   102→    snprintf(path, path_size, "%s/.shadowsocks_%s.conf", prefix, server->port);
   103→    FILE *f = fopen(path, "w+");
   104→    if (f == NULL) {
   105→        if (verbose) {
   106→            LOGE("unable to open config file");
   107→        }
   108→        ss_free(path);
   109→        return;
   110→    }
   111→    fprintf(f, "{\n");
   112→    fprintf(f, "\"server_port\":\"%s\",\n", server->port);
   113→    fprintf(f, "\"password\":\"%s\",\n", server->password);
   114→    fprintf(f, "}\n");
   115→    fclose(f);
   116→    ss_free(path);
   117→}
   118→
   119→static char *
   120→construct_command_line(struct manager_ctx *manager, struct server *server)
   121→{
   122→    static char cmd[BUF_SIZE];
   123→    int i;
   124→
   125→    build_config(working_dir, server);
   126→
   127→    memset(cmd, 0, BUF_SIZE);
   128→    snprintf(cmd, BUF_SIZE,
   129→             "%s -m %s --manager-address %s -f %s/.shadowsocks_%s.pid -c %s/.shadowsocks_%s.conf",
   130→             executable, manager->method, manager->manager_address,
   131→             working_dir, server->port, working_dir, server->port);
   132→
   133→    if (manager->acl != NULL) {
   134→        int len = strlen(cmd);
   135→        snprintf(cmd + len, BUF_SIZE - len, " --acl %s", manager->acl);
   136→    }
   137→    if (manager->timeout != NULL) {
   138→        int len = strlen(cmd);
   139→        snprintf(cmd + len, BUF_SIZE - len, " -t %s", manager->timeout);
   140→    }
   141→#ifdef HAVE_SETRLIMIT
   142→    if (manager->nofile) {
   143→        int len = strlen(cmd);
   144→        snprintf(cmd + len, BUF_SIZE - len, " -n %d", manager->nofile);
   145→    }
   146→#endif
   147→    if (manager->user != NULL) {
   148→        int len = strlen(cmd);
   149→        snprintf(cmd + len, BUF_SIZE - len, " -a %s", manager->user);
   150→    }
   151→    if (manager->verbose) {
   152→        int len = strlen(cmd);
   153→        snprintf(cmd + len, BUF_SIZE - len, " -v");
   154→    }
   155→    if (manager->mode == UDP_ONLY) {
   156→        int len = strlen(cmd);
   157→        snprintf(cmd + len, BUF_SIZE - len, " -U");
   158→    }
   159→    if (manager->mode == TCP_AND_UDP) {
   160→        int len = strlen(cmd);
   161→        snprintf(cmd + len, BUF_SIZE - len, " -u");
   162→    }
   163→    if (manager->auth) {
   164→        int len = strlen(cmd);
   165→        snprintf(cmd + len, BUF_SIZE - len, " -A");
   166→    }
   167→    if (manager->fast_open) {
   168→        int len = strlen(cmd);
   169→        snprintf(cmd + len, BUF_SIZE - len, " --fast-open");
   170→    }
   171→    if (manager->mtu) {
   172→        int len = strlen(cmd);
   173→        snprintf(cmd + len, BUF_SIZE - len, " --mtu %d", manager->mtu);
   174→    }
   175→    for (i = 0; i < manager->nameserver_num; i++) {
   176→        int len = strlen(cmd);
   177→        snprintf(cmd + len, BUF_SIZE - len, " -d %s", manager->nameservers[i]);
   178→    }
   179→    for (i = 0; i < manager->host_num; i++) {
   180→        int len = strlen(cmd);
   181→        snprintf(cmd + len, BUF_SIZE - len, " -s %s", manager->hosts[i]);
   182→    }
   183→
   184→    if (verbose) {
   185→        LOGI("cmd: %s", cmd);
   186→    }
   187→
   188→    return cmd;
   189→}
   190→
   191→static char *
   192→get_data(char *buf, int len)
   193→{
   194→    char *data;
   195→    int pos = 0;
   196→
   197→    while (buf[pos] != '{' && pos < len)
   198→        pos++;
   199→    if (pos == len) {
   200→        return NULL;
   201→    }
   202→    data = buf + pos - 1;
   203→
   204→    return data;
   205→}
   206→
   207→static char *
   208→get_action(char *buf, int len)
   209→{
   210→    char *action;
   211→    int pos = 0;
   212→
   213→    while (isspace((unsigned char)buf[pos]) && pos < len)
   214→        pos++;
   215→    if (pos == len) {
   216→        return NULL;
   217→    }
   218→    action = buf + pos;
   219→
   220→    while ((!isspace((unsigned char)buf[pos]) && buf[pos] != ':') && pos < len)
   221→        pos++;
   222→    buf[pos] = '\0';
   223→
   224→    return action;
   225→}
   226→
   227→static struct server *
   228→get_server(char *buf, int len)
   229→{
   230→    char *data = get_data(buf, len);
   231→    char error_buf[512];
   232→
   233→    if (data == NULL) {
   234→        LOGE("No data found");
   235→        return NULL;
   236→    }
   237→
   238→    json_settings settings = { 0 };
   239→    json_value *obj        = json_parse_ex(&settings, data, strlen(data), error_buf);
   240→
   241→    if (obj == NULL) {
   242→        LOGE("%s", error_buf);
   243→        return NULL;
   244→    }
   245→
   246→    struct server *server = ss_malloc(sizeof(struct server));
   247→    memset(server, 0, sizeof(struct server));
   248→    if (obj->type == json_object) {
   249→        int i = 0;
   250→        for (i = 0; i < obj->u.object.length; i++) {
   251→            char *name        = obj->u.object.values[i].name;
   252→            json_value *value = obj->u.object.values[i].value;
   253→            if (strcmp(name, "server_port") == 0) {
   254→                if (value->type == json_string) {
   255→                    strncpy(server->port, value->u.string.ptr, 8);
   256→                } else if (value->type == json_integer) {
   257→                    snprintf(server->port, 8, "%" PRIu64 "", value->u.integer);
   258→                }
   259→            } else if (strcmp(name, "password") == 0) {
   260→                if (value->type == json_string) {
   261→                    strncpy(server->password, value->u.string.ptr, 128);
   262→                }
   263→            } else {
   264→                LOGE("invalid data: %s", data);
   265→                break;
   266→            }
   267→        }
   268→    }
   269→
   270→    json_value_free(obj);
   271→    return server;
   272→}
   273→
   274→static int
   275→parse_traffic(char *buf, int len, char *port, uint64_t *traffic)
   276→{
   277→    char *data = get_data(buf, len);
   278→    char error_buf[512];
   279→    json_settings settings = { 0 };
   280→
   281→    if (data == NULL) {
   282→        LOGE("No data found");
   283→        return -1;
   284→    }
   285→
   286→    json_value *obj = json_parse_ex(&settings, data, strlen(data), error_buf);
   287→    if (obj == NULL) {
   288→        LOGE("%s", error_buf);
   289→        return -1;
   290→    }
   291→
   292→    if (obj->type == json_object) {
   293→        int i = 0;
   294→        for (i = 0; i < obj->u.object.length; i++) {
   295→            char *name        = obj->u.object.values[i].name;
   296→            json_value *value = obj->u.object.values[i].value;
   297→            if (value->type == json_integer) {
   298→                strncpy(port, name, 8);
   299→                *traffic = value->u.integer;
   300→            }
   301→        }
   302→    }
   303→
   304→    json_value_free(obj);
   305→    return 0;
   306→}
   307→
   308→static void
   309→add_server(struct manager_ctx *manager, struct server *server)
   310→{
   311→    bool new = false;
   312→    cork_hash_table_put(server_table, (void *)server->port, (void *)server, &new, NULL, NULL);
   313→
   314→    char *cmd = construct_command_line(manager, server);
   315→    if (system(cmd) == -1) {
   316→        ERROR("add_server_system");
   317→    }
   318→}
   319→
   320→static void
   321→kill_server(char *prefix, char *pid_file)
   322→{
   323→    char *path = NULL;
   324→    int pid, path_size = strlen(prefix) + strlen(pid_file) + 2;
   325→    path = ss_malloc(path_size);
   326→    snprintf(path, path_size, "%s/%s", prefix, pid_file);
   327→    FILE *f = fopen(path, "r");
   328→    if (f == NULL) {
   329→        if (verbose) {
   330→            LOGE("unable to open pid file");
   331→        }
   332→        ss_free(path);
   333→        return;
   334→    }
   335→    if (fscanf(f, "%d", &pid) != EOF) {
   336→        kill(pid, SIGTERM);
   337→    }
   338→    fclose(f);
   339→    remove(path);
   340→    ss_free(path);
   341→}
   342→
   343→static void
   344→stop_server(char *prefix, char *port)
   345→{
   346→    char *path = NULL;
   347→    int pid, path_size = strlen(prefix) + strlen(port) + 20;
   348→    path = ss_malloc(path_size);
   349→    snprintf(path, path_size, "%s/.shadowsocks_%s.pid", prefix, port);
   350→    FILE *f = fopen(path, "r");
   351→    if (f == NULL) {
   352→        if (verbose) {
   353→            LOGE("unable to open pid file");
   354→        }
   355→        ss_free(path);
   356→        return;
   357→    }
   358→    if (fscanf(f, "%d", &pid) != EOF) {
   359→        kill(pid, SIGTERM);
   360→    }
   361→    fclose(f);
   362→    ss_free(path);
   363→}
   364→
   365→static void
   366→remove_server(char *prefix, char *port)
   367→{
   368→    char *old_port            = NULL;
   369→    struct server *old_server = NULL;
   370→
   371→    cork_hash_table_delete(server_table, (void *)port, (void **)&old_port, (void **)&old_server);
   372→
   373→    if (old_server != NULL) {
   374→        ss_free(old_server);
   375→    }
   376→
   377→    stop_server(prefix, port);
   378→}
   379→
   380→static void
   381→update_stat(char *port, uint64_t traffic)
   382→{
   383→    void *ret = cork_hash_table_get(server_table, (void *)port);
   384→    if (ret != NULL) {
   385→        struct server *server = (struct server *)ret;
   386→        server->traffic = traffic;
   387→    }
   388→}
   389→
   390→static void
   391→manager_recv_cb(EV_P_ ev_io *w, int revents)
   392→{
   393→    struct manager_ctx *manager = (struct manager_ctx *)w;
   394→    socklen_t len;
   395→    size_t r;
   396→    struct sockaddr_un claddr;
   397→    char buf[BUF_SIZE];
   398→
   399→    memset(buf, 0, BUF_SIZE);
   400→
   401→    len = sizeof(struct sockaddr_un);
   402→    r   = recvfrom(manager->fd, buf, BUF_SIZE, 0, (struct sockaddr *)&claddr, &len);
   403→    if (r == -1) {
   404→        ERROR("manager_recvfrom");
   405→        return;
   406→    }
   407→
   408→    if (r > BUF_SIZE / 2) {
   409→        LOGE("too large request: %d", (int)r);
   410→        return;
   411→    }
   412→
   413→    char *action = get_action(buf, r);
   414→    if (action == NULL) {
   415→        return;
   416→    }
   417→
   418→    if (strcmp(action, "add") == 0) {
   419→        struct server *server = get_server(buf, r);
   420→
   421→        if (server == NULL || server->port[0] == 0 || server->password[0] == 0) {
   422→            LOGE("invalid command: %s:%s", buf, get_data(buf, r));
   423→            if (server != NULL) {
   424→                ss_free(server);
   425→            }
   426→            goto ERROR_MSG;
   427→        }
   428→
   429→        remove_server(working_dir, server->port);
   430→        add_server(manager, server);
   431→
   432→        char msg[3] = "ok";
   433→        if (sendto(manager->fd, msg, 2, 0, (struct sockaddr *)&claddr, len) != 2) {
   434→            ERROR("add_sendto");
   435→        }
   436→    } else if (strcmp(action, "remove") == 0) {
   437→        struct server *server = get_server(buf, r);
   438→
   439→        if (server == NULL || server->port[0] == 0) {
   440→            LOGE("invalid command: %s:%s", buf, get_data(buf, r));
   441→            if (server != NULL) {
   442→                ss_free(server);
   443→            }
   444→            goto ERROR_MSG;
   445→        }
   446→
   447→        remove_server(working_dir, server->port);
   448→        ss_free(server);
   449→
   450→        char msg[3] = "ok";
   451→        if (sendto(manager->fd, msg, 2, 0, (struct sockaddr *)&claddr, len) != 2) {
   452→            ERROR("remove_sendto");
   453→        }
   454→    } else if (strcmp(action, "stat") == 0) {
   455→        char port[8];
   456→        uint64_t traffic = 0;
   457→
   458→        if (parse_traffic(buf, r, port, &traffic) == -1) {
   459→            LOGE("invalid command: %s:%s", buf, get_data(buf, r));
   460→            return;
   461→        }
   462→
   463→        update_stat(port, traffic);
   464→    } else if (strcmp(action, "ping") == 0) {
   465→        struct cork_hash_table_entry *entry;
   466→        struct cork_hash_table_iterator server_iter;
   467→
   468→        char buf[BUF_SIZE];
   469→
   470→        memset(buf, 0, BUF_SIZE);
   471→        sprintf(buf, "stat: {");
   472→
   473→        cork_hash_table_iterator_init(server_table, &server_iter);
   474→
   475→        while ((entry = cork_hash_table_iterator_next(&server_iter)) != NULL) {
   476→            struct server *server = (struct server *)entry->value;
   477→            size_t pos            = strlen(buf);
   478→            if (pos > BUF_SIZE / 2) {
   479→                buf[pos - 1] = '}';
   480→                if (sendto(manager->fd, buf, pos, 0, (struct sockaddr *)&claddr, len)
   481→                    != pos) {
   482→                    ERROR("ping_sendto");
   483→                }
   484→                memset(buf, 0, BUF_SIZE);
   485→            } else {
   486→                sprintf(buf + pos, "\"%s\":%" PRIu64 ",", server->port, server->traffic);
   487→            }
   488→        }
   489→
   490→        size_t pos = strlen(buf);
   491→        if (pos > 7) {
   492→            buf[pos - 1] = '}';
   493→        } else {
   494→            buf[pos] = '}';
   495→            pos++;
   496→        }
   497→
   498→        if (sendto(manager->fd, buf, pos, 0, (struct sockaddr *)&claddr, len)
   499→            != pos) {
   500→            ERROR("ping_sendto");
   501→        }
   502→    }
   503→
   504→    return;
   505→
   506→ERROR_MSG:
   507→    strcpy(buf, "err");
   508→    if (sendto(manager->fd, buf, 3, 0, (struct sockaddr *)&claddr, len) != 3) {
   509→        ERROR("error_sendto");
   510→    }
   511→}
   512→
   513→static void
   514→signal_cb(EV_P_ ev_signal *w, int revents)
   515→{
   516→    if (revents & EV_SIGNAL) {
   517→        switch (w->signum) {
   518→        case SIGINT:
   519→        case SIGTERM:
   520→            ev_unloop(EV_A_ EVUNLOOP_ALL);
   521→        }
   522→    }
   523→}
   524→
   525→int
   526→create_server_socket(const char *host, const char *port)
   527→{
   528→    struct addrinfo hints;
   529→    struct addrinfo *result, *rp, *ipv4v6bindall;
   530→    int s, server_sock;
   531→
   532→    memset(&hints, 0, sizeof(struct addrinfo));
   533→    hints.ai_family   = AF_UNSPEC;               /* Return IPv4 and IPv6 choices */
   534→    hints.ai_socktype = SOCK_DGRAM;              /* We want a UDP socket */
   535→    hints.ai_flags    = AI_PASSIVE | AI_ADDRCONFIG; /* For wildcard IP address */
   536→    hints.ai_protocol = IPPROTO_UDP;
   537→
   538→    s = getaddrinfo(host, port, &hints, &result);
   539→    if (s != 0) {
   540→        LOGE("getaddrinfo: %s", gai_strerror(s));
   541→        return -1;
   542→    }
   543→
   544→    rp = result;
   545→
   546→    /*
   547→     * On Linux, with net.ipv6.bindv6only = 0 (the default), getaddrinfo(NULL) with
   548→     * AI_PASSIVE returns 0.0.0.0 and :: (in this order). AI_PASSIVE was meant to
   549→     * return a list of addresses to listen on, but it is impossible to listen on
   550→     * 0.0.0.0 and :: at the same time, if :: implies dualstack mode.
   551→     */
   552→    if (!host) {
   553→        ipv4v6bindall = result;
   554→
   555→        /* Loop over all address infos found until a IPV6 address is found. */
   556→        while (ipv4v6bindall) {
   557→            if (ipv4v6bindall->ai_family == AF_INET6) {
   558→                rp = ipv4v6bindall; /* Take first IPV6 address available */
   559→                break;
   560→            }
   561→            ipv4v6bindall = ipv4v6bindall->ai_next; /* Get next address info, if any */
   562→        }
   563→    }
   564→
   565→    for (/*rp = result*/; rp != NULL; rp = rp->ai_next) {
   566→        server_sock = socket(rp->ai_family, rp->ai_socktype, rp->ai_protocol);
   567→        if (server_sock == -1) {
   568→            continue;
   569→        }
   570→
   571→        if (rp->ai_family == AF_INET6) {
   572→            int ipv6only = host ? 1 : 0;
   573→            setsockopt(server_sock, IPPROTO_IPV6, IPV6_V6ONLY, &ipv6only, sizeof(ipv6only));
   574→        }
   575→
   576→        int opt = 1;
   577→        setsockopt(server_sock, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));
   578→
   579→        s = bind(server_sock, rp->ai_addr, rp->ai_addrlen);
   580→        if (s == 0) {
   581→            /* We managed to bind successfully! */
   582→            break;
   583→        } else {
   584→            ERROR("bind");
   585→        }
   586→
   587→        close(server_sock);
   588→    }
   589→
   590→    if (rp == NULL) {
   591→        LOGE("cannot bind");
   592→        return -1;
   593→    }
   594→
   595→    freeaddrinfo(result);
   596→
   597→    return server_sock;
   598→}
   599→
   600→int
   601→main(int argc, char **argv)
   602→{
   603→    int i, c;
   604→    int pid_flags         = 0;
   605→    char *acl             = NULL;
   606→    char *user            = NULL;
   607→    char *password        = NULL;
   608→    char *timeout         = NULL;
   609→    char *method          = NULL;
   610→    char *pid_path        = NULL;
   611→    char *conf_path       = NULL;
   612→    char *iface           = NULL;
   613→    char *manager_address = NULL;
   614→
   615→    int auth      = 0;
   616→    int fast_open = 0;
   617→    int mode      = TCP_ONLY;
   618→    int mtu       = 0;
   619→
   620→#ifdef HAVE_SETRLIMIT
   621→    static int nofile = 0;
   622→#endif
   623→
   624→    int server_num = 0;
   625→    char *server_host[MAX_REMOTE_NUM];
   626→
   627→    char *nameservers[MAX_DNS_NUM + 1];
   628→    int nameserver_num = 0;
   629→
   630→    jconf_t *conf = NULL;
   631→
   632→    int option_index                    = 0;
   633→    static struct option long_options[] = {
   634→        { "fast-open",       no_argument,       0, 0 },
   635→        { "acl",             required_argument, 0, 0 },
   636→        { "manager-address", required_argument, 0, 0 },
   637→        { "executable",      required_argument, 0, 0 },
   638→        { "mtu",             required_argument, 0, 0 },
   639→        { "help",            no_argument,       0, 0 },
   640→        {                 0,                 0, 0, 0 }
   641→    };
   642→
   643→    opterr = 0;
   644→
   645→    USE_TTY();
   646→
   647→    while ((c = getopt_long(argc, argv, "f:s:l:k:t:m:c:i:d:a:n:huUvA",
   648→                            long_options, &option_index)) != -1)
   649→        switch (c) {
   650→        case 0:
   651→            if (option_index == 0) {
   652→                fast_open = 1;
   653→            } else if (option_index == 1) {
   654→                acl = optarg;
   655→            } else if (option_index == 2) {
   656→                manager_address = optarg;
   657→            } else if (option_index == 3) {
   658→                executable = optarg;
   659→            } else if (option_index == 4) {
   660→                mtu = atoi(optarg);
   661→                LOGI("set MTU to %d", mtu);
   662→            } else if (option_index == 5) {
   663→                usage();
   664→                exit(EXIT_SUCCESS);
   665→            }
   666→            break;
   667→        case 's':
   668→            if (server_num < MAX_REMOTE_NUM) {
   669→                server_host[server_num++] = optarg;
   670→            }
   671→            break;
   672→        case 'k':
   673→            password = optarg;
   674→            break;
   675→        case 'f':
   676→            pid_flags = 1;
   677→            pid_path  = optarg;
   678→            break;
   679→        case 't':
   680→            timeout = optarg;
   681→            break;
   682→        case 'm':
   683→            method = optarg;
   684→            break;
   685→        case 'c':
   686→            conf_path = optarg;
   687→            break;
   688→        case 'i':
   689→            iface = optarg;
   690→            break;
   691→        case 'd':
   692→            if (nameserver_num < MAX_DNS_NUM) {
   693→                nameservers[nameserver_num++] = optarg;
   694→            }
   695→            break;
   696→        case 'a':
   697→            user = optarg;
   698→            break;
   699→        case 'u':
   700→            mode = TCP_AND_UDP;
   701→            break;
   702→        case 'U':
   703→            mode = UDP_ONLY;
   704→            break;
   705→        case 'v':
   706→            verbose = 1;
   707→            break;
   708→        case 'h':
   709→            usage();
   710→            exit(EXIT_SUCCESS);
   711→        case 'A':
   712→            auth = 1;
   713→            break;
   714→#ifdef HAVE_SETRLIMIT
   715→        case 'n':
   716→            nofile = atoi(optarg);
   717→            break;
   718→#endif
   719→        case '?':
   720→            // The option character is not recognized.
   721→            LOGE("Unrecognized option: %s", optarg);
   722→            opterr = 1;
   723→            break;
   724→        }
   725→
   726→    if (opterr) {
   727→        usage();
   728→        exit(EXIT_FAILURE);
   729→    }
   730→
   731→    if (conf_path != NULL) {
   732→        conf = read_jconf(conf_path);
   733→        if (server_num == 0) {
   734→            server_num = conf->remote_num;
   735→            for (i = 0; i < server_num; i++)
   736→                server_host[i] = conf->remote_addr[i].host;
   737→        }
   738→        if (password == NULL) {
   739→            password = conf->password;
   740→        }
   741→        if (method == NULL) {
   742→            method = conf->method;
   743→        }
   744→        if (timeout == NULL) {
   745→            timeout = conf->timeout;
   746→        }
   747→        if (user == NULL) {
   748→            user = conf->user;
   749→        }
   750→#ifdef TCP_FASTOPEN
   751→        if (fast_open == 0) {
   752→            fast_open = conf->fast_open;
   753→        }
   754→#endif
   755→        if (conf->nameserver != NULL) {
   756→            nameservers[nameserver_num++] = conf->nameserver;
   757→        }
   758→        if (auth == 0) {
   759→            auth = conf->auth;
   760→        }
   761→        if (mode == TCP_ONLY) {
   762→            mode = conf->mode;
   763→        }
   764→        if (mtu == 0) {
   765→            mtu = conf->mtu;
   766→        }
   767→#ifdef HAVE_SETRLIMIT
   768→        if (nofile == 0) {
   769→            nofile = conf->nofile;
   770→        }
   771→#endif
   772→    }
   773→
   774→    if (server_num == 0) {
   775→        server_host[server_num++] = "0.0.0.0";
   776→    }
   777→
   778→    if (method == NULL) {
   779→        method = "table";
   780→    }
   781→
   782→    if (timeout == NULL) {
   783→        timeout = "60";
   784→    }
   785→
   786→    if (pid_flags) {
   787→        USE_SYSLOG(argv[0]);
   788→        daemonize(pid_path);
   789→    }
   790→
   791→    if (server_num == 0 || manager_address == NULL) {
   792→        usage();
   793→        exit(EXIT_FAILURE);
   794→    }
   795→
   796→    if (fast_open == 1) {
   797→#ifdef TCP_FASTOPEN
   798→        LOGI("using tcp fast open");
   799→#else
   800→        LOGE("tcp fast open is not supported by this environment");
   801→#endif
   802→    }
   803→
   804→    if (auth) {
   805→        LOGI("onetime authentication enabled");
   806→    }
   807→
   808→#ifdef __MINGW32__
   809→    winsock_init();
   810→#else
   811→    // ignore SIGPIPE
   812→    signal(SIGPIPE, SIG_IGN);
   813→    signal(SIGCHLD, SIG_IGN);
   814→    signal(SIGABRT, SIG_IGN);
   815→#endif
   816→
   817→    struct ev_signal sigint_watcher;
   818→    struct ev_signal sigterm_watcher;
   819→    ev_signal_init(&sigint_watcher, signal_cb, SIGINT);
   820→    ev_signal_init(&sigterm_watcher, signal_cb, SIGTERM);
   821→    ev_signal_start(EV_DEFAULT, &sigint_watcher);
   822→    ev_signal_start(EV_DEFAULT, &sigterm_watcher);
   823→
   824→    struct manager_ctx manager;
   825→    memset(&manager, 0, sizeof(struct manager_ctx));
   826→
   827→    manager.fast_open       = fast_open;
   828→    manager.verbose         = verbose;
   829→    manager.mode            = mode;
   830→    manager.auth            = auth;
   831→    manager.password        = password;
   832→    manager.timeout         = timeout;
   833→    manager.method          = method;
   834→    manager.iface           = iface;
   835→    manager.acl             = acl;
   836→    manager.user            = user;
   837→    manager.manager_address = manager_address;
   838→    manager.hosts           = server_host;
   839→    manager.host_num        = server_num;
   840→    manager.nameservers     = nameservers;
   841→    manager.nameserver_num  = nameserver_num;
   842→    manager.mtu             = mtu;
   843→#ifdef HAVE_SETRLIMIT
   844→    manager.nofile = nofile;
   845→#endif
   846→
   847→    // initialize ev loop
   848→    struct ev_loop *loop = EV_DEFAULT;
   849→
   850→    // setuid
   851→    if (user != NULL && ! run_as(user)) {
   852→        FATAL("failed to switch user");
   853→    }
   854→
   855→#ifndef __MINGW32__
   856→    if (geteuid() == 0){
   857→        LOGI("running from root user");
   858→    }
   859→#endif
   860→
   861→    struct passwd *pw   = getpwuid(getuid());
   862→    const char *homedir = pw->pw_dir;
   863→    working_dir_size = strlen(homedir) + 15;
   864→    working_dir      = ss_malloc(working_dir_size);
   865→    snprintf(working_dir, working_dir_size, "%s/.shadowsocks", homedir);
   866→
   867→    int err = mkdir(working_dir, S_IRWXU | S_IRWXG | S_IROTH | S_IXOTH);
   868→    if (err != 0 && errno != EEXIST) {
   869→        ERROR("mkdir");
   870→        ss_free(working_dir);
   871→        FATAL("unable to create working directory");
   872→    }
   873→
   874→    // Clean up all existed processes
   875→    DIR *dp;
   876→    struct dirent *ep;
   877→    dp = opendir(working_dir);
   878→    if (dp != NULL) {
   879→        while ((ep = readdir(dp)) != NULL) {
   880→            size_t len = strlen(ep->d_name);
   881→            if (strcmp(ep->d_name + len - 3, "pid") == 0) {
   882→                kill_server(working_dir, ep->d_name);
   883→                if (verbose)
   884→                    LOGI("kill %s", ep->d_name);
   885→            }
   886→        }
   887→        closedir(dp);
   888→    } else {
   889→        ss_free(working_dir);
   890→        FATAL("Couldn't open the directory");
   891→    }
   892→
   893→    server_table = cork_string_hash_table_new(MAX_PORT_NUM, 0);
   894→
   895→    if (conf != NULL) {
   896→        for (i = 0; i < conf->port_password_num; i++) {
   897→            struct server *server = ss_malloc(sizeof(struct server));
   898→            memset(server, 0, sizeof(struct server));
   899→            strncpy(server->port, conf->port_password[i].port, 8);
   900→            strncpy(server->password, conf->port_password[i].password, 128);
   901→            add_server(&manager, server);
   902→        }
   903→    }
   904→
   905→    int sfd;
   906→    ss_addr_t ip_addr = { .host = NULL, .port = NULL };
   907→    parse_addr(manager_address, &ip_addr);
   908→
   909→    if (ip_addr.host == NULL || ip_addr.port == NULL) {
   910→        struct sockaddr_un svaddr;
   911→        sfd = socket(AF_UNIX, SOCK_DGRAM, 0);       /*  Create server socket */
   912→        if (sfd == -1) {
   913→            ss_free(working_dir);
   914→            FATAL("socket");
   915→        }
   916→
   917→        setnonblocking(sfd);
   918→
   919→        if (remove(manager_address) == -1 && errno != ENOENT) {
   920→            ERROR("bind");
   921→            ss_free(working_dir);
   922→            exit(EXIT_FAILURE);
   923→        }
   924→
   925→        memset(&svaddr, 0, sizeof(struct sockaddr_un));
   926→        svaddr.sun_family = AF_UNIX;
   927→        strncpy(svaddr.sun_path, manager_address, sizeof(svaddr.sun_path) - 1);
   928→
   929→        if (bind(sfd, (struct sockaddr *)&svaddr, sizeof(struct sockaddr_un)) == -1) {
   930→            ERROR("bind");
   931→            ss_free(working_dir);
   932→            exit(EXIT_FAILURE);
   933→        }
   934→    } else {
   935→        sfd = create_server_socket(ip_addr.host, ip_addr.port);
   936→        if (sfd == -1) {
   937→            ss_free(working_dir);
   938→            FATAL("socket");
   939→        }
   940→    }
   941→
   942→    manager.fd = sfd;
   943→    ev_io_init(&manager.io, manager_recv_cb, manager.fd, EV_READ);
   944→    ev_io_start(loop, &manager.io);
   945→
   946→    // start ev loop
   947→    ev_run(loop, 0);
   948→
   949→    if (verbose) {
   950→        LOGI("closed gracefully");
   951→    }
   952→
   953→    // Clean up
   954→    struct cork_hash_table_entry *entry;
   955→    struct cork_hash_table_iterator server_iter;
   956→
   957→    cork_hash_table_iterator_init(server_table, &server_iter);
   958→
   959→    while ((entry = cork_hash_table_iterator_next(&server_iter)) != NULL) {
   960→        struct server *server = (struct server *)entry->value;
   961→        stop_server(working_dir, server->port);
   962→    }
   963→
   964→#ifdef __MINGW32__
   965→    winsock_cleanup();
   966→#endif
   967→
   968→    ev_signal_stop(EV_DEFAULT, &sigint_watcher);
   969→    ev_signal_stop(EV_DEFAULT, &sigterm_watcher);
   970→    ss_free(working_dir);
   971→
   972→    return 0;
   973→}
